final:
module top_module(
    input [31:0] obf_A,
    input [31:0] B,
    input [1:0] sel,
    output reg [31:0] Z
);always @(*) begin
    case (sel)
        2'b00: Z = obf_A + B;
        2'b01: Z = obf_A - B;
        2'b10: Z = obf_A * B;
        2'b11: Z = B ? obf_A / B : 0;
        default: Z = 0;
    endcase
end

endmodule
